class Admin_Model_GopayPayment extends Admin_Model_Base_GopayPayment {

    /**
     * @param Doctrine_Connection|null $conn
     */
    public function save(Doctrine_Connection $conn = null) {
        if ($this->ID == null) {
            $this->Date = date('Y-m-d');
            $this->Time = date('H:i:s');
        }

        parent::save($conn);
    }

    /**
     * @param int $orderID
     * @param int $gopayID
     * @param string $gopayURL
     * @return Admin_Model_GopayPayment
     */
    public static function createGopayPayment(int $orderID, int $gopayID, string $gopayURL): self {
        $gopayPayment = new Admin_Model_GopayPayment();
        $gopayPayment->Order_ID = $orderID;
        $gopayPayment->GopayID = $gopayID;
        $gopayPayment->GopayURL = $gopayURL;
        $gopayPayment->save();

        return $gopayPayment;
    }

    /**
     * @param int $gopayID
     * @return array
     */
    public static function getPaymentByGopayID(int $gopayID): array {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_GopayPayment object');
        $query->where('object.GopayID = ?', $gopayID);

        return $query->execute()->toArray();
    }
}